import React, { useContext } from "react";
import { GeneralContext } from "./GeneralContext";
import { watchlist } from "../data/data";

// Import exact Material UI Icons to match Zerodha toolbelt layout
import BarChartOutlinedIcon from "@mui/icons-material/BarChartOutlined";
import ListOutlinedIcon from "@mui/icons-material/ListOutlined";
import DeleteOutlineOutlinedIcon from "@mui/icons-material/DeleteOutlineOutlined";
import MoreHorizOutlinedIcon from "@mui/icons-material/MoreHorizOutlined";

const WatchListElement = ({ stock }) => {
  // 1. UPDATED: Extracted handleOpenSellWindow from your context pipeline
  const { handleOpenBuyWindow, handleOpenSellWindow } =
    useContext(GeneralContext);

  // Safely check down status to match your index.css colors (.up or .down)
  const isStockDown = stock.isDown ?? true;

  return (
    <li>
      <div className="item">
        {/* Stock name on the left side with active color context */}
        <p className={isStockDown ? "down" : "up"}>{stock.name}</p>

        {/* Percentage change and Price aligned on the right side */}
        <div className="item-info">
          <span className="percent">{stock.percent}</span>
          <span className="price">{Number(stock.price).toFixed(2)}</span>
        </div>
      </div>

      {/* Action overlay panel matching the design configuration */}
      <div className="actions">
        <span className="actions-buttons">
          {/* Buy Button Icon Box */}
          <button
            className="buy-btn"
            onClick={() => handleOpenBuyWindow(stock.name)}
          >
            B
          </button>

          {/* Sell Button Icon Box - 2. FIXED: Wired up your operational onClick listener */}
          <button
            className="sell-btn"
            onClick={() => handleOpenSellWindow(stock.name)}
          >
            S
          </button>

          {/* Market Depth Tool Option */}
          <button className="icon-btn" title="Market Depth">
            <ListOutlinedIcon className="mui-icon" />
          </button>

          {/* Technical Charts Tool Option */}
          <button className="icon-btn" title="Chart">
            <BarChartOutlinedIcon className="mui-icon" />
          </button>

          {/* Remove From Watchlist Tool Option */}
          <button className="icon-btn" title="Delete">
            <DeleteOutlineOutlinedIcon className="mui-icon" />
          </button>

          {/* Context Menu Extension Tool Option */}
          <button className="icon-btn" title="More">
            <MoreHorizOutlinedIcon className="mui-icon" />
          </button>
        </span>
      </div>
    </li>
  );
};

const WatchList = () => {
  return (
    <div className="watchlist-container">
      <div className="search-container">
        <input
          type="text"
          name="search"
          id="search"
          placeholder="Search eg: infy, bse, nifty fut weekly, gold mcx"
          className="search"
        />
        <span className="counts">{watchlist.length} / 50</span>
      </div>

      <ul className="list">
        {watchlist.map((stock, index) => {
          return <WatchListElement stock={stock} key={index} />;
        })}
      </ul>
    </div>
  );
};

export default WatchList;
